import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button } from '../components/ui/Button';
import { Organization } from '../types';
import { generateId } from '../lib/utils';
import { Check, ChevronRight, ChevronLeft, Building, Palette, Briefcase, Users, Shield, MessageSquare } from 'lucide-react';

const steps = [
  { id: 'identity', label: 'Identity', icon: Building },
  { id: 'brand', label: 'Brand', icon: Palette },
  { id: 'services', label: 'Services', icon: Briefcase },
  { id: 'team', label: 'Team', icon: Users },
  { id: 'compliance', label: 'Trust', icon: Shield },
  { id: 'voice', label: 'Voice', icon: MessageSquare },
];

export const Wizard: React.FC = () => {
  const navigate = useNavigate();
  const [activeStep, setActiveStep] = useState(0);
  const [formData, setFormData] = useState<Partial<Organization>>({
    name: '',
    industry: '',
    brand: { colors: { primary: '#000000', secondary: '#ffffff', accent: '#3b82f6' }, font_vibe: 'Modern' },
    voice_profile: { tone: 'Professional', reading_level: 'High School', banned_phrases: [] },
    services: [],
    team: [],
    compliance: []
  });

  const handleNext = () => {
    if (activeStep < steps.length - 1) {
      setActiveStep(prev => prev + 1);
    } else {
      // Simulate save
      console.log('Saving Organization:', formData);
      navigate('/dashboard');
    }
  };

  const handleBack = () => {
    if (activeStep > 0) setActiveStep(prev => prev - 1);
  };

  const StepContent = () => {
    switch (activeStep) {
      case 0:
        return (
          <div className="space-y-6 animate-fade-in">
            <h2 className="text-2xl font-bold text-slate-900">Company Identity</h2>
            <p className="text-slate-500">Let's start with the basics of your organization.</p>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Company Name</label>
                <input 
                  type="text" 
                  className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none transition-all"
                  placeholder="e.g. Acme Corp"
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Industry</label>
                <select 
                  className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none bg-white"
                  value={formData.industry}
                  onChange={e => setFormData({...formData, industry: e.target.value})}
                >
                  <option value="">Select Industry</option>
                  <option value="SaaS">SaaS</option>
                  <option value="Healthcare">Healthcare</option>
                  <option value="Finance">Finance</option>
                  <option value="E-commerce">E-commerce</option>
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Company Domain</label>
                <input 
                  type="text" 
                  className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
                  placeholder="acme.com"
                />
              </div>
            </div>
          </div>
        );
      case 1:
        return (
          <div className="space-y-6 animate-fade-in">
            <h2 className="text-2xl font-bold text-slate-900">Brand Kit</h2>
            <p className="text-slate-500">Define the visual feeling of your brand.</p>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               <div className="space-y-2">
                 <label className="text-sm font-medium text-slate-700">Primary Color</label>
                 <div className="flex gap-2">
                   <input type="color" className="h-10 w-20 rounded cursor-pointer" 
                    value={formData.brand?.colors.primary}
                    onChange={e => setFormData({
                      ...formData, 
                      brand: { ...formData.brand!, colors: { ...formData.brand!.colors, primary: e.target.value } }
                    })}
                   />
                   <input type="text" className="flex-1 p-2 border border-slate-300 rounded-lg" value={formData.brand?.colors.primary} readOnly />
                 </div>
               </div>
               <div className="space-y-2">
                 <label className="text-sm font-medium text-slate-700">Typography Vibe</label>
                 <div className="grid grid-cols-2 gap-3">
                   {['Modern', 'Classic', 'Tech', 'Playful'].map(vibe => (
                     <button 
                       key={vibe}
                       onClick={() => setFormData({ ...formData, brand: { ...formData.brand!, font_vibe: vibe } })}
                       className={`p-3 border rounded-lg text-sm font-medium transition-all ${
                         formData.brand?.font_vibe === vibe 
                         ? 'border-brand-500 bg-brand-50 text-brand-700' 
                         : 'border-slate-200 hover:border-slate-300 text-slate-600'
                       }`}
                     >
                       {vibe}
                     </button>
                   ))}
                 </div>
               </div>
            </div>
          </div>
        );
      case 2:
      case 3:
      case 4:
      case 5:
        return (
           <div className="space-y-6 animate-fade-in text-center py-12">
             <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-400">
               {React.createElement(steps[activeStep].icon, { size: 32 })}
             </div>
             <h2 className="text-2xl font-bold text-slate-900">Step: {steps[activeStep].label}</h2>
             <p className="text-slate-500 max-w-md mx-auto">
               This step would contain specific form fields for {steps[activeStep].label.toLowerCase()}. 
               (Simplified for this demo).
             </p>
             <div className="p-4 bg-yellow-50 border border-yellow-200 rounded-lg inline-block text-yellow-800 text-sm">
               Mock Mode: Clicking "Next" will bypass detailed entry.
             </div>
           </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-slate-900">Create Profile</h1>
        <p className="text-slate-500">Define your organization's truth for AI consistency.</p>
      </div>

      <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden">
        {/* Progress Bar */}
        <div className="bg-slate-50 border-b border-slate-200 p-4">
          <div className="flex justify-between items-center relative">
             {/* Line */}
             <div className="absolute top-1/2 left-0 w-full h-0.5 bg-slate-200 -z-0"></div>

             {steps.map((step, idx) => {
               const isActive = idx === activeStep;
               const isCompleted = idx < activeStep;
               return (
                 <div key={step.id} className="relative z-10 flex flex-col items-center gap-2">
                   <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all duration-300 ${
                     isActive ? 'bg-brand-600 border-brand-600 text-white shadow-lg scale-110' :
                     isCompleted ? 'bg-green-500 border-green-500 text-white' :
                     'bg-white border-slate-300 text-slate-400'
                   }`}>
                     {isCompleted ? <Check size={18} /> : React.createElement(step.icon, { size: 18 })}
                   </div>
                   <span className={`text-xs font-medium hidden md:block ${isActive ? 'text-brand-700' : 'text-slate-500'}`}>
                     {step.label}
                   </span>
                 </div>
               );
             })}
          </div>
        </div>

        {/* Form Body */}
        <div className="p-8 min-h-[400px]">
          <StepContent />
        </div>

        {/* Footer */}
        <div className="bg-slate-50 border-t border-slate-200 p-6 flex justify-between items-center">
          <Button variant="ghost" onClick={handleBack} disabled={activeStep === 0} className="gap-2">
            <ChevronLeft size={16} /> Back
          </Button>
          <div className="flex gap-4">
            <Button variant="ghost" onClick={() => navigate('/dashboard')}>Save Draft</Button>
            <Button onClick={handleNext} className="gap-2">
              {activeStep === steps.length - 1 ? 'Finish & Generate' : 'Next Step'} <ChevronRight size={16} />
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

