                  </Button>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
                 <div className="p-4 bg-red-50 rounded-lg border border-red-100">
                   <h4 className="text-xs font-bold text-red-800 uppercase mb-2 flex items-center gap-2">
