              </div>
            </div>

            <div className="bg-slate-900 rounded-xl border border-slate-800 flex flex-col flex-1 overflow-hidden shadow-2xl">
              <div className="bg-slate-800 px-4 py-2 border-b border-slate-700 flex justify-between items-center">
