import { GoogleGenAI, Type } from "@google/genai";
import { ServiceItem, ComplianceItem, TeamMember } from '../types';

// In a real app, this would be a server-side route. 
// For this demo, we assume process.env.API_KEY is available or injected.
const apiKey = process.env.API_KEY || 'dummy-key'; 
const ai = new GoogleGenAI({ apiKey });

const MODEL_NAME = 'gemini-2.5-flash-preview';

export const generateServices = async (industry: string, companyName: string): Promise<ServiceItem[]> => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Generate 3 key service offerings for a ${industry} company named ${companyName}. Include concrete outcomes.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              description: { type: Type.STRING },
              outcomes: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];
    const data = JSON.parse(text);
    return data.map((item: any, index: number) => ({
      ...item,
      id: `generated-service-${index}-${Date.now()}`
    }));
  } catch (error) {
    console.error("AI Generation Error:", error);
    // Fallback for demo if API key fails
    return [
      { id: 'err-1', name: 'Strategic Consulting', description: 'Expert guidance for your business.', outcomes: ['Improved efficiency'] },
      { id: 'err-2', name: 'Platform Implementation', description: 'Deployment of core systems.', outcomes: ['Faster time to market'] }
    ];
  }
};

export const generateCompliance = async (industry: string): Promise<ComplianceItem[]> => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `List 3 key compliance frameworks required for the ${industry} industry.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              framework: { type: Type.STRING },
              details: { type: Type.STRING },
              status: { type: Type.STRING, enum: ["Certified", "Compliant", "In Progress"] }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text).map((item: any, idx: number) => ({ ...item, id: `comp-${idx}` }));
  } catch (error) {
    return [];
  }
};

export const generateTeamStructure = async (industry: string): Promise<TeamMember[]> => {
   try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Suggest a typical team structure for a ${industry} company.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              role: { type: Type.STRING },
              description: { type: Type.STRING },
              count: { type: Type.INTEGER }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text).map((item: any, idx: number) => ({ ...item, id: `team-${idx}` }));
  } catch (error) {
    return [];
  }
};

import React, { useState } from 'react';
import { Sparkles, Loader2 } from 'lucide-react';
import { Button } from './Button';

interface MagicButtonProps {
  onClick: () => Promise<void>;
  label?: string;
  className?: string;
  disabled?: boolean;
}

export const MagicButton: React.FC<MagicButtonProps> = ({ onClick, label = "Auto-fill with AI", className, disabled }) => {
  const [loading, setLoading] = useState(false);

  const handleClick = async () => {
    setLoading(true);
    try {
      await onClick();
    } finally {
      setLoading(false);
    }
  };

  return (
    <Button 
      variant="outline" 
      size="sm" 
      onClick={handleClick} 
      disabled={loading || disabled}
      className={`text-indigo-600 border-indigo-200 hover:bg-indigo-50 ${className}`}
    >
      {loading ? <Loader2 size={16} className="mr-2 animate-spin" /> : <Sparkles size={16} className="mr-2" />}
      {loading ? 'Generating...' : label}
    </Button>
  );
};

