import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { MOCK_ORGS, MOCK_PERSONAS } from '../constants';
import { generatePersonaExport } from '../services/adapterService';
import { Button } from '../components/ui/Button';
import { Copy, Check, Download, AlertTriangle, ShieldCheck, History, RotateCcw, ArrowLeft } from 'lucide-react';
import { cn } from '../lib/utils';
import { Organization, OrganizationVersion } from '../types';

export const OrgDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();

  // Local state to allow modification/restoration in this session
  const [org, setOrg] = useState<Organization | undefined>(undefined);
  const [personas, setPersonas] = useState(MOCK_PERSONAS);
  const [selectedPersonaId, setSelectedPersonaId] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [history, setHistory] = useState<OrganizationVersion[]>([]);

  // Initialize data
  useEffect(() => {
    const foundOrg = MOCK_ORGS.find(o => o.id === id);
    if (foundOrg) {
      setOrg(foundOrg);
      const orgPersonas = MOCK_PERSONAS.filter(p => p.organization_id === id);
      setPersonas(orgPersonas);
      if (orgPersonas.length > 0) setSelectedPersonaId(orgPersonas[0].id);

      // Generate Mock History based on the found org
      setHistory([
        { 
          id: 'v2', 
          organization_id: foundOrg.id, 
          version_number: 2, 
          data: { ...foundOrg }, // Current state
          created_by: 'You', 
          created_at: 'Just now', 
          change_summary: 'Current Version' 
        },
        { 
          id: 'v1', 
          organization_id: foundOrg.id, 
          version_number: 1, 
          data: { 
            ...foundOrg, 
            services: foundOrg.services.slice(0, 1), // Fewer services in old version
            compliance: [] // No compliance in old version
          }, 
          created_by: 'System', 
          created_at: '2 days ago', 
          change_summary: 'Initial Setup' 
        }
      ]);
    }
  }, [id]);

  if (!org) return <div className="p-8 text-center text-slate-500">Organization not found.</div>;

  const selectedPersona = personas.find(p => p.id === selectedPersonaId);
  const exportContent = selectedPersona ? generatePersonaExport(org, selectedPersona) : '';

  const handleCopy = () => {
    navigator.clipboard.writeText(exportContent);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleRestore = (version: OrganizationVersion) => {
    if (confirm(`Restore version from ${version.created_at}? Current unsaved changes will be lost.`)) {
      setOrg({ ...org, ...version.data } as Organization);
      setShowHistory(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-[calc(100vh-140px)]">
      {/* Sidebar List */}
      <div className="lg:col-span-3 bg-white rounded-xl border border-slate-200 overflow-hidden flex flex-col shadow-sm">
        <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center h-14">
           {showHistory ? (
             <div className="flex items-center gap-2 cursor-pointer text-slate-600 hover:text-slate-900" onClick={() => setShowHistory(false)}>
               <ArrowLeft size={16} /> <span className="font-semibold text-sm">Back</span>
             </div>
           ) : (
             <div>
              <h3 className="font-semibold text-slate-900 text-sm">Personas</h3>
              <p className="text-[10px] text-slate-500 uppercase tracking-wider">Select to Preview</p>
             </div>
           )}
           <button 
             onClick={() => setShowHistory(!showHistory)} 
             className={cn(
               "p-2 rounded transition-colors", 
               showHistory ? "bg-brand-100 text-brand-700" : "hover:bg-slate-200 text-slate-500"
             )}
             title="Version History"
           >
             <History size={18} />
           </button>
        </div>

        {showHistory ? (
          <div className="flex-1 overflow-auto p-2 space-y-2 bg-slate-50/50">
             {history.map((v, idx) => (
               <div key={v.id} className="p-3 border border-slate-200 rounded-lg bg-white shadow-sm hover:border-brand-300 transition-all group relative">
                  <div className="flex justify-between items-center mb-1">
                    <span className="font-semibold text-slate-700 text-sm">Version {history.length - idx}</span>
                    <span className="text-[10px] text-slate-400">{v.created_at}</span>
                  </div>
                  <div className="text-xs text-slate-500 mb-3">{v.change_summary}</div>

                  {idx === 0 ? (
                    <span className="inline-block px-2 py-0.5 bg-green-100 text-green-700 text-[10px] font-medium rounded-full">Current</span>
                  ) : (
                    <Button 
                      size="sm" 
                      variant="outline" 
                      className="w-full text-xs h-7 gap-1 hover:bg-brand-50 hover:text-brand-700 hover:border-brand-200"
                      onClick={() => handleRestore(v)}
                    >
                      <RotateCcw size={12} /> Restore
                    </Button>
                  )}
               </div>
             ))}
