                                            <div className="mt-2 text-xs text-slate-500 space-y-1">
                                                {change.current.map((s: any) => <div key={s.id}>• {s.name}</div>)}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
