                 <div className="p-4 bg-slate-50 rounded-lg border border-slate-100 md:col-span-2">
                   <h4 className="text-xs font-bold text-slate-600 uppercase mb-3">Capabilities</h4>
                   <div className="flex flex-wrap gap-2">
                     {selectedPersona.capabilities.map((c, i) => (
                       <span key={i} className="text-sm bg-white border border-slate-200 px-3 py-1.5 rounded-md text-slate-700 shadow-sm">
                         {c}
                       </span>
                     ))}
