                 </div>
              </div>
            </div>

            <div className="bg-slate-900 rounded-xl border border-slate-800 flex flex-col flex-1 overflow-hidden shadow-2xl ring-1 ring-slate-900/5">
              <div className="bg-slate-800 px-4 py-3 border-b border-slate-700 flex justify-between items-center">
                 <div className="flex items-center gap-2">
                    <span className="text-xs font-mono text-slate-400 uppercase tracking-wider">Prompt Preview</span>
                    <span className="text-xs px-1.5 py-0.5 rounded bg-slate-700 text-slate-300 border border-slate-600 font-mono">
                      {selectedPersona.platform}
                    </span>
                 </div>
                 <div className="flex gap-1.5 opacity-60">
                   <div className="w-2.5 h-2.5 rounded-full bg-slate-500"></div>
                   <div className="w-2.5 h-2.5 rounded-full bg-slate-500"></div>
                   <div className="w-2.5 h-2.5 rounded-full bg-slate-500"></div>
                 </div>
              </div>
              <div className="p-6 overflow-auto custom-scrollbar bg-[#0f172a]">
                <pre className="font-mono text-sm text-slate-300 whitespace-pre-wrap leading-relaxed">
                  {exportContent}
                </pre>
              </div>
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center bg-white rounded-xl border-2 border-slate-200 border-dashed p-12 text-center">
            <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4 text-slate-300">
               <ShieldCheck size={32} />
            </div>
            <h3 className="text-lg font-medium text-slate-900">No Persona Selected</h3>
            <p className="text-slate-500 mt-2 max-w-sm">Select a persona from the sidebar to view its configuration, constraints, and generated prompt.</p>
          </div>
        )}
      </div>
    </div>
  );
};

